// teléfono
const telefono = $('WhatsApp Trigger').first().json.messages[0].from;

// mensaje usuario limpio
let mensajeUsuario = $('WhatsApp Trigger').first().json.messages[0].text.body.toLowerCase();

// palabras basura
const stopWords = [
  "el","la","los","las","un","una","unos","unas",
  "de","del","que","quiero","necesito","por","favor"
];

function limpiar(texto){
  return texto
    .normalize("NFD").replace(/[\u0300-\u036f]/g, "") // quitar acentos
    .replace(/[.,!?;:()"]/g, "") // quitar puntuación
    .split(" ")
    .filter(p => !stopWords.includes(p) && p.trim() !== "")
    .join(" ");
}

mensajeUsuario = limpiar(mensajeUsuario);

// filas
const filas = $input.all();

let mejorRespuesta = null;
let mejorImagenes = null;
let mejorScore = 0;

const palabrasMensaje = new Set(mensajeUsuario.split(" "));

// comparar
for (const fila of filas) {
  let problema = (fila.json.Problemas || "").toLowerCase();
  problema = limpiar(problema);

  const palabrasProblema = problema.split(" ");

  let score = palabrasProblema.filter(p => palabrasMensaje.has(p)).length;

  if(score > mejorScore){
    mejorScore = score;
    mejorRespuesta = fila.json.Soluciones;
    mejorImagenes = fila.json.Imágenes;
  }
}

// Construir objeto dinámico
let resultado = {
  telefono,
  mensajeUsuario,
  respuestaFAQ: mejorScore > 0 ? mejorRespuesta : null
};

// Separar imágenes en imagen1, imagen2...
if(mejorScore > 0 && mejorImagenes){
  const listaImagenes = mejorImagenes.replace(/\n/g,' ').split(/[\s,]+/).filter(Boolean);
  listaImagenes.forEach((url, index) => {
    resultado[`imagen${index + 1}`] = url;
  });
}

// devolver estructura final
return [{ json: resultado }];
